sql:
SELECT DISTINCT ps.protein_name
FROM access_logs al
JOIN protein_structures ps ON al.structure_id = ps.structure_id;

SELECT COUNT(structure_id)
FROM protein_structures
WHERE lab = (SELECT lab_id FROM labs WHERE lab_name = 'TFN');

external_knowledge:
-"latest version" refers to the version with the highest version number or most recent version date; 
-"most recently created protein structure" refers to the structure with the most recent creation date; 
-Root Mean Square Deviation (RMSD) is a measure of the average distance between the atoms of superimposed proteins; 
-MCQ (Molecular Characterization of Proteins) is a measure used for evaluating protein-ligand interactions; 
-TM-score is a measure of the similarity between two protein structures; 
- ranking versions by version date in descending order means getting the most recent version first.

sql:
SELECT lab, COUNT(structure_id) AS structures_per_lab
FROM protein_structures
GROUP BY lab;

SELECT protein_name, rmsd
FROM protein_structures
ORDER BY rmsd ASC;
